import React, { useRef, useEffect, useReducer } from 'react';
import "../../styles/slider.css";
// Slayt verileri
const slides = [
  {
    title: "A-Ether | Merkeziyetsiz Finansın Geleceği",
    subtitle: "",
    description: "Adventure is never far away",
    image: "https://res.cloudinary.com/dazvkvpch/image/upload/v1772544671/aether-dikey-logo.png"
  },
  {
    title: "Aether Hizmetleri ile Tanışın",
    description: "Let your dreams come true",
    image: "https://res.cloudinary.com/dazvkvpch/image/upload/v1772561952/aether-slider-logo.png"
  },
  {
    title: "Mimisa Rocks",
    description: "A piece of heaven",
    image: "https://images.unsplash.com/photo-1566522650166-bd8b3e3a2b4b?ixlib=rb-1.2.1&q=80&fm=jpg&crop=entropy&cs=tinysrgb&w=800&fit=max"
  },
  {
    title: "Four",
    description: "A piece of heaven",
    image: "https://images.unsplash.com/flagged/photo-1564918031455-72f4e35ba7a6?ixlib=rb-1.2.1&q=80&fm=jpg&crop=entropy&cs=tinysrgb&w=800&fit=max"
  },
  {
    title: "Five",
    description: "A piece of heaven",
    image: "https://images.unsplash.com/photo-1579130781921-76e18892b57b?ixlib=rb-1.2.1&q=80&fm=jpg&crop=entropy&cs=tinysrgb&w=800&fit=max"
  }
];

// Tilt Hook'u
function useTilt(active) {
  const ref = useRef(null);

  useEffect(() => {
    if (!ref.current || !active) return;

    const el = ref.current;
    let rect;

    const handleMouseMove = (e) => {
      if (!el) return;
      if (!rect) rect = el.getBoundingClientRect();
      
      const px = (e.clientX - rect.left) / rect.width;
      const py = (e.clientY - rect.top) / rect.height;

      el.style.setProperty("--px", px);
      el.style.setProperty("--py", py);
    };

    el.addEventListener("mousemove", handleMouseMove);

    return () => {
      el.removeEventListener("mousemove", handleMouseMove);
    };
  }, [active]);

  return ref;
}

const initialState = {
  slideIndex: 0
};

const slidesReducer = (state, event) => {
  if (event.type === "NEXT") {
    return {
      ...state,
      slideIndex: (state.slideIndex + 1) % slides.length
    };
  }
  if (event.type === "PREV") {
    return {
      ...state,
      slideIndex: state.slideIndex === 0 ? slides.length - 1 : state.slideIndex - 1
    };
  }
  return state;
};

// Alt Bileşen: Slide
function Slide({ slide, offset }) {
  const active = offset === 0;
  const ref = useTilt(active);

  return (
    <div
      ref={ref}
      className="slide"
      data-active={active || undefined}
      style={{
        "--offset": offset,
        "--dir": offset === 0 ? 0 : offset > 0 ? 1 : -1
      }}
    >
     
      <div
        className="slideContent"
        style={{ backgroundImage: `url('${slide.image}')` }}
      >
        <div className="slideContentInner">
          <h2 className="slideTitle">{slide.title}</h2>
          <h3 className="slideSubtitle">{slide.subtitle}</h3>
          <p className="slideDescription">{slide.description}</p>
        </div>
      </div>
    </div>
  );
}

// Ana Bileşen: App
export default function App() {
  const [state, dispatch] = useReducer(slidesReducer, initialState);

  return (
    <div className="slides">
      <button onClick={() => dispatch({ type: "PREV" })}>‹</button>

      {[...slides, ...slides, ...slides].map((slide, i) => {
        let offset = slides.length + (state.slideIndex - i);
        return <Slide slide={slide} offset={offset} key={i} />;
      })}
      
      <button onClick={() => dispatch({ type: "NEXT" })}>›</button>
    </div>
  );
}
